-- ---------------------------------------------------------------------------
-- Conditional Regular-pool drops, as static rule tables (maps + gates). These
-- layer onto the Regular pool when their condition is live. The three sources
-- and their gates are encoded here so digcalc / the panel can mark each one
-- active or inactive against the live Vana'diel clock.
-- ---------------------------------------------------------------------------
cond = {

  -- Weather crystals/clusters: the current weather's element yields that
  -- element's crystal (~10% in any digging zone, no rank gate); double weather
  -- yields the cluster instead. byElement maps the 8 elements to the standard
  -- FFXI crystal/cluster item ids. Weather element -> crystal is a pure lookup;
  -- the panel resolves the live weather element to the row.
  crystals = {
    chance  = 10,     -- ~10% per dig, any digging zone
    minRank = 0,      -- no rank requirement
    byElement = {
      Fire      = { crystal = 4096, cluster = 4104 },
      Ice       = { crystal = 4097, cluster = 4105 },
      Wind      = { crystal = 4098, cluster = 4106 },
      Earth     = { crystal = 4099, cluster = 4107 },
      Lightning = { crystal = 4100, cluster = 4108 },
      Water     = { crystal = 4101, cluster = 4109 },
      Light     = { crystal = 4102, cluster = 4110 },
      Dark      = { crystal = 4103, cluster = 4111 },
    },
  },

  -- Day rocks: the current Vana'diel day's element yields that element's rock
  -- (~5% in any digging zone, requires dig rank >= Novice). byDay maps the 8
  -- Vana'diel days to their element; byElement carries the concrete rock item
  -- id/name PER ELEMENT -- RESOLVED BY THE GENERATOR from the server's item
  -- constants (empty here; see DATA STATUS). The day->element map + the gate
  -- are the stable, well-formed part.
  rocks = {
    chance  = 5,      -- ~5% per dig, any digging zone
    minRank = 3,      -- >= Novice
    byDay = {
      Firesday     = "Fire",
      Iceday       = "Ice",
      Windsday     = "Wind",
      Earthsday    = "Earth",
      Lightningday = "Lightning",
      Watersday    = "Water",
      Lightsday    = "Light",
      Darksday     = "Dark",
    },
    byElement = {
      Fire      = { id = 769, n = "Red Rock" },
      Ice       = { id = 773, n = "Translucent Rock" },
      Wind      = { id = 772, n = "Green Rock" },
      Earth     = { id = 771, n = "Yellow Rock" },
      Lightning = { id = 774, n = "Purple Rock" },
      Water     = { id = 770, n = "Blue Rock" },
      Light     = { id = 776, n = "White Rock" },
      Dark      = { id = 775, n = "Black Rock" },
    },
  },

  -- Day ores: the current day's element yields that element's ore, but only
  -- under the full gate -- dig rank >= Craftsman, the matching elemental weather
  -- is up, the Vana'diel moon phase percent is within 7..21, and only in the 9 elemental-
  -- ore zones (~10% there). byDay maps day->element; byElement carries the ore
  -- item id/name per element (generated); zones is the elemental-ore zone set
  -- (generated). The maps + gate are the stable part.
  ores = {
    chance  = 10,     -- ~10% per dig, ore zones only
    minRank = 6,      -- >= Craftsman
    requiresElementalWeather = true,
    moonPhaseWindow = { min = 7, max = 21 },   -- moon phase percent (0-100, = VanadielMoonPhase) window
    byDay = {
